const Q_ECONOMICS_1998=[{"id": "objective>Economics>1998>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, full employment indicated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Any point on the curve indicate full employment of resources , technologically efficient or resources are fully utilized.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1998>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">unity of consumption of commodity X</td><td style=\"border:1px solid black;text-align:center;\"> Marginal utility (Units)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> 100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\"> 80</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\"> 50</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 20</td></tr></table></div> <br/> From the table above, the total utility for the individual who consumes 3 units of commodity X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50 utils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 utils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">230 utils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250 utils</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total utility is the addition of all marginal utilities. Therefore for 3 units consumed by the consumer, we have: <br/> Total utility = 100+ 80 + 50 <br/> = 230 utils</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>1998>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the economic problems of Nigeria today arises from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the overutilization of human and natural resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unavailability of mineral resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate manpower resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the under-utilization of human and natural resources</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The under-utilization of resources and human are one of the major problem Nigeria is facing in the economy.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1998>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In certain circumstances, a centrally planned economy adopts the rationing system because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the scarcity of goods and services in the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low real and money wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the need for equitable distribution of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation and distribution problems</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A centrally planned economy adopts the rationing system because of the scarcity of goods and services in the market. Rationing is a system of distributing scarce goods and services using criteria other than price. In a centrally planned economy, the government controls all major aspects of economic production and distribution, and thus, when goods and services are scarce, the government may resort to rationing to ensure that everyone gets an equal share of the limited resources.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1998>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that <br/> B = Births <br/> D = Deaths <br/> X = Emigrants <br/> M = Immigrants <br/> The population of a country of a country over a period of time will rise if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">B = D and X > M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B - D = O and M > X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D - B = O and M = X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X > M and D > B</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total population is calculated as: Br - Dr + (Net migration i.e I - E) <br/> Therefore the population of the country is : B- D and M- X</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>1998>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table to answer questions below <br/> Population statistics of a country <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">AGE RANGE IN YEARS</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">% OF POPULATION</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 1960</td><td style=\"border:1px solid black;text-align:center;\"> 1990</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60 and above</td><td style=\"border:1px solid black;text-align:center;\"> 35</td><td style=\"border:1px solid black;text-align:center;\"> 38</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">18 - 59</td><td style=\"border:1px solid black;text-align:center;\"> 40</td><td style=\"border:1px solid black;text-align:center;\"> 42</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">0 - 17</td><td style=\"border:1px solid black;text-align:center;\"> 25</td><td style=\"border:1px solid black;text-align:center;\"> 20</td></tr></table></div> <br/>  <br/> The dependency ratio between 1960 and 1990 is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased by 5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased by 2%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by 2%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by 5%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For 1960 = 35 + 25 <br/> = 60 <br/>  <br/> For 1990 = 38 + 20 <br/> = 58 <br/>  <br/> Difference = 60 - 58 <br/> = 2 <br/> Therefore, there is a decrease of 2% between 1960 and 1990</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>1998>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table to answer questions below <br/> Population statistics of a country <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">AGE RANGE IN YEARS</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">% OF POPULATION</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 1960</td><td style=\"border:1px solid black;text-align:center;\"> 1990</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60 and above</td><td style=\"border:1px solid black;text-align:center;\"> 35</td><td style=\"border:1px solid black;text-align:center;\"> 38</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">18 - 59</td><td style=\"border:1px solid black;text-align:center;\"> 40</td><td style=\"border:1px solid black;text-align:center;\"> 42</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">0 - 17</td><td style=\"border:1px solid black;text-align:center;\"> 25</td><td style=\"border:1px solid black;text-align:center;\"> 20</td></tr></table></div> <br/> In 1990, the difference between the dependent population and the active population ratio is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For 1990, Dependent Population = 38 + 20  <br/> = 58 <br/>  <br/> Independent ( active) population = 42 <br/>  <br/> Difference = 58 - 42 <br/> = 16%</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>1998>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run period in production is defined as a period when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is at least one fixed factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all costs of production must be covered </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the output cannot be varied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current output is not profitable</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A short run period is a period of time in which some factors are fixed and some are variable. For a firm to continue to produce in the short run, the firm must cover its average variable cost.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>1998>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Specialization often improves economic performance because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">permits exploitation of economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incorporates external economies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is based on the law of variable proportions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocate resources according to absolute advantage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Specialization often improves economic performance because it permits exploitation of economies of scale. Economies of scale refer to the cost advantage experienced by a firm when it increases its level of output.The advantage arises due to the inverse relationship between per-unit fixed cost and the quantity produced. The efficiency of the overall production process increases through an increase in production levels.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>1998>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements best describes the relationship between average product and marginal product?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal product and average product curves rise and fall together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal product equals average product at the minimum point of the latter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average product curve will rise as long as marginal product is greater than average product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal product equals average product at the maximum point of the former</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal product (MP) and average product (AP) initially increase and then decrease due to the operation of the Law of Diminishing Marginal Returns. As long as MP is higher than AP, AP increases. At the highest point of AP, i,e when AP is at its maximum, MP is equal to AP. When MP becomes lesser than AP, AP also starts to fall. Thereafter, both Ap and MP fall , but MP becomes negative and AP remains positive.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>1998>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Total output (units)</td><td style=\"border:1px solid black;text-align:center;\"> Fixed Cost (#)</td><td style=\"border:1px solid black;text-align:center;\"> Variable cost (#)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">100</td><td style=\"border:1px solid black;text-align:center;\"> 100</td><td style=\"border:1px solid black;text-align:center;\"> 100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">120</td><td style=\"border:1px solid black;text-align:center;\"> 100</td><td style=\"border:1px solid black;text-align:center;\"> 110</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">160</td><td style=\"border:1px solid black;text-align:center;\"> 100</td><td style=\"border:1px solid black;text-align:center;\"> 120</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">200</td><td style=\"border:1px solid black;text-align:center;\"> 100</td><td style=\"border:1px solid black;text-align:center;\"> 140</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">240</td><td style=\"border:1px solid black;text-align:center;\"> 100</td><td style=\"border:1px solid black;text-align:center;\"> 160</td></tr></table></div> <br/> The average total cost when output is 200 units in the table above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1.20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2.40</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">TC = FC + VC <br/> = 100 + 140 <br/> = 240 <br/>  <br/> ATC = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">TC</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">q</span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">240</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">200</span> <br/>  <br/> = #1.2</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>1998>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a firm is reaping economies of large-scale production, it experiences a fall in its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long-run marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-run average cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-run total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-run marginal cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the long run average costs fall as more output is produced, the firm is expericing economies of scale.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>1998>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the price P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> in price control situation is reffered to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minimum price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mark-up price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mark-down price</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minimun price control are set above the equilibrium price i.e when supply is greater than demand. To identify it, there is a connection of a line connecting the demand curve and supply curve above the equilibrium price in the diagram above.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>1998>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The shaded triangle in the diagram above is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer surplus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shaded portion in the diagram above represent consumer surplus which shows the difference between what a consumer budgeted to pay for a commodity and the actual amount he paid for the commodity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>1998>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> is the original demand curve, S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> is the original supply curve ,D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is the new demand curve and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is the new supply curve. <br/> What is the new equilibrium quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium quantity is Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> where the new demand and supply curve intersect.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>1998>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an increase in the price of a commodity leads to increase in total revenue, then it means that the demand for this commodity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abnormal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand is inelastic, an increase in price leads to an increase in total revenue, and a decrease in price leads to a fall in total revenue.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1998>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that the elasticity of demand for a commodity is 2.5, the percentage change in the quantity demanded as a result of a 10 percent change in its price is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">% ∆ in Qd</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> % ∆ in P</span> <br/>  <br/> e = 2.5 <br/> % ∆ in Qd = ?  <br/> %% ∆ in P =  10 <br/>  <br/>  2.5 = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">% ∆ in Qd</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 10</span> <br/>  <br/> 2.5  x 10 = % ∆ in Qd <br/> % ∆ in Qd = 25%</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1998>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The producer in a perfectly competitive market is faced with a demand curve whose elasticity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unitary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than one</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The producer confronts an infinitely elastic demand for its product. <br/> Note that: the demand curve of a perfectly competitive market is downward sloping and it is different from a perfectly competitive firm with a horizontal demand curve.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>1998>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In  the diagram above, profit is maximized at the output level </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ON</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OL</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OF</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Profit is maximized when the MC curve cuts the MR from below. It should be noted that at N, MC only intersect MR. Therefore, profit is not maximized but at  L, the MC curve cuts the MR from below.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>1998>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unlike the retailer, the wholesaler provides</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">useful information to the manufacturer about consumers' tastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">after-sales service to the consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">useful information to the customers on the benefits and uses of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">useful information about market trends and finance to the manufacturer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unlike retailers, wholesalers often provide manufacturers with valuable insights about the market trends, demand patterns and financial information. This feedback helps manufacturers adjust their production and marketing strategies accordingly</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>1998>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Liquidation of limited liability company implies that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">company may not pay its debts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debts of the company can only be paid from its own assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debts of the company are paid from both business and private funds of the owners </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debts of the company must be paid from public funds only.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liquidation of a company is when the company's assets are sold and the company ceases operations and is deregistered. The assets are sold to pay back various claimants, such as creditors and shareholders. It occurs when the company is insolvent i.e it can no longer meets its financial obligations.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1998>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One form of business organization which is not motivated solely by the profit objective is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint stock company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">private limited company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-operative society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary partnership</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Co-operative society is a voluntary business organisation in which a group of individuals with common interest pool their resources together to promote the economic welfare of ther members in production, distribution and consumption of goods and services.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>1998>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can have their shares quoted on the stock exchange?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public corporations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a partnership </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a consumer cooperative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a public limited liability company</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public limited liability is a company that allows the public to subcribe to its shares and must have a minimum number prescribed. Shares are easily transfered and also the shares are quoted in the stock exchange.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>1998>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sector that employs the largest proportion of the active labour force in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal civil service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financial sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agricultural sector</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture in Nigeria is the practice of cultivating the lands and rearing livestock for food and commercial purposes. According to a World Bank survey, the agriculture sector is the largest employer of labour and income -generating activity in Nigeria.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1998>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An entirely domestic effort directed at improving agricultural production in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Agricultural Development Programme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agro-Industrial Development Scheme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Food and Agricultural Organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National land Development Authority</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural Development Project started in 1975 and was co-financed by the World Bank, Federal and State government to: <br/> - to increase the level of extension contact with farmers <br/> - to source and make available farm input to farmers <br/> - to boost agricultural production through the construction of farm service centres for efficient distribution of agricultural input.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>1998>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A factor that influences the location of a firm near its market is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation of bulky raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external economies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of transporting finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of skilled manpower</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There should be ready market for the products of any industry to be sited in a place, fragile goods like glass, bulky goods like cement and other perishable goods should be located near the market. <br/>  <br/> Also, neareness to market reduces the cost of transportation and meets high demand by consumers.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1998>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In many developing countries, infrastructural problem is acute due to the shortage of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industries and industrial equipment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">savings, investment and consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural resources for development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supporting services that encourage economic activities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The operational capacity of the existing infrastructure is poor for a number of reasons: the acute shortage of skilled manpower, poor skills of workers, scarcity of operating funds, at the operational and management level poor planning leads to weakness in resolving the problems.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1998>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Export-promotion policy is primarily concerned with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">processing of raw materials to increase their value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making of international routes safe for export commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction in the number of imported items</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouragement of the production of export commodities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Export promotion strategy is a delibrate government policy aimed at encouraging the production of commodities for export.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>1998>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The petroleum industry in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the sole source of the nation's revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the oldest industry in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mainstay of the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a factor in the decline in the nation's foreign reserves</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oil and gas industry has a significant impact on the Nigeria's economy. This is the reason why successive governments have remained focused on the sector despite various discussion on diversifying the economy.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1998>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Crude petroleum is a good example of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lasting asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wasting asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synthetic product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">costless resource</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A wasting asset is a type of asset that has a limited life span and its value keeps on decreasing. It can be vehicles , natural resources like crude oil, coal mines, machinery etc.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>1998>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the techniques of monetary control used by the central bank of Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">selective credit control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget deficit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monitoring the general price level</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Selective credit control refers to a method in which the Central bank gives directions to other banks to give or not give credit for certain purposes to the particular sector. The selective credit control method of monetary policy includes those instruments which focus on the selected sectors of the economy and not the size of the total credit in the economy as it quantitative method used by the central bank.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1998>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true about the value of money?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it varies inversely with the price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it varies directly with the price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it depreciates in the period of deflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is not affected by the price level</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The value of money varies inversely with the price level. If the price level increases, this would mean that a given sum of money would buy fewer goods and services. The value of money therefore falls with an increase in the price level.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>1998>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the reserve requirement for commercial banking in nigeria were 30%, a commercial bank which receives an initial cash deposit of #3,000 is in a position to lend out </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#9000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3330</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2770</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2100</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amount to be lend out = 3000 - ( 30%  x 3,000) <br/>  = 3,000 - 900 <br/> = #2,100</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1998>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An issue of bank-notes not backed by gold but by government securities is known a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fiduciary issue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guaranteed money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">signiorage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal tender</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An issue of bank-notes not backed by gold but by government securities is known as a fiduciary issue. Fiduciary issue refers to the portion of a country's money supply that is not backed by gold or other precious metals but instead by trust in the government that issued it. The term 'fiduciary' comes from the Latin word for 'trust'.</div>", "topic": "MONEY : TYPES OF MONEY"}, {"id": "objective>Economics>1998>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rise in the market price of fixed interest securities is an indication that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply of money has decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidity preference has increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">market rate of interest has risen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market rate of interest has fallen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fixed interest security is a debt instrument such as a bond, debenture or gilt edged bond that investors use to loan money to a company in exchange for intetest payments.  Since their interest rate is fixed, these securities will become less valuable as rates go up in a rising interst environment. If interest rates fall, however, the fixed interest security becomes more valuable because there is an inverse relationship between bond prices and interest rates, the value of the investor's bond will fall to reflect the higher interest rate in the market.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1998>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in government expenditure will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">investment opportunities for foreign investors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the level of aggregate demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in total tax revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction in total tax revenue</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Keynesian economics, increased government expenditure/spending raises aggregate demand and increases consumption which leads to increased production and faster recovery from recessions.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1998>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an indirect tax is levied on the producer of a good, the burden on the consumer will demand largely on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elasticity of demand for the good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proportion of the consumer's income spent on the good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elasticities of demand and supply of the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of substitutes for the commodity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an indirect tax is levied on the producer of a good, the burden on the consumer will demand largely on the elasticity of demand for the good. </div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>1998>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a government wants to reduce the level of inflation, it will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">run a budget surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">run a budget deficit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">run a balanced budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">borrow more money</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Budget surplus occurs when the government revenue exceeds the proposed government expenditure. It is used to control inflation and to reduce aggregate spending.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1998>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a country national income increased from #1000 billion to #1100 billion over a period of 2 years. what was the average annual rate of growth of national income over the period ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Annual growth rate = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1100 - 1000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1000</span>  x 100 <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">100</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1000</span>  x 100 <br/>  <br/> = 10 <br/> For 2 periods, we have <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">10</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> <br/> = 5% increase</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1998>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fall in the marginal propensity to save will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in national income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no change in national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in disposable income</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The MPS measures the slope of the saving line. Thus, if MPC increases and MPS falls, the saving line becomes flatter i.e its slope falls.As a result equilibrium national income will increase.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION"}, {"id": "objective>Economics>1998>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is transfer payment?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dividend to a shareholder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gift to a motherless babies' home</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salary to a worker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent to a landlord</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transfer payment are payments or receipts not resulting from contribution to productive activities in the economy. They are mere transfers from one person to another i.e money received but not earn for example: gift, bursary, award, unemployment benefit etc. When calculating and estimating national income, transfer payment are excluded in order to avoid double counting.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>1998>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major objective of economic growth is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">redistribute income and other benefits of growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equalize opportunities for education and employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the aggregate expenditure on goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the real per capita income</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aim of economic growth and develoment is to improve the material standards of living by raising teh absolute level of per capita incomes. Raising per capita incomes is also a stated objective of the policy of the governments of all developing countries.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1998>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The family support programme in Nigeria essentially focuses on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the generation of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the alleviation of poverty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agricultural and industrial development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic emancipation of women</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Family Support Programme (FSP) in Nigeria was established with the primary aim of alleviating poverty. The programme was designed to provide direct and immediate assistance to the most vulnerable groups in society, including women, children, and the elderly. It focused on areas such as health, education, and income generation, with the overall goal of improving the living conditions of these groups and reducing poverty.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1998>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economically, underdeveloped countries are characterized by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high rate of population growth and low rate of economic growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high rate of economic growth and low rate of population growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high rate of population growth and high rate of economic growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low rate of population frowth and low rate of economic growth</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a country as compared to its natural resources and other productive facilities, has a population that falls short of its needs, it is said to be under populated. It also exist when the people within the country are to few in number to supply enough labour to tap the available resources. <br/>  <br/> NOTE THAT: if there is an increase in population and also the per capita income rises, it means the country is underpopulated.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1998>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major consequences of urban-biased development programmes in Nigeria is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">led to rapid rural-urban migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">led to unpredecented urban wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transformed rural areas into urban centres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased the level of specialized manpower in the cities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major consequences of urban-biased development programmes in Nigeria is that they led to rapid rural-urban migration</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1998>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Development plans have not been successful in some developing countries largely becasue of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">very large working population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing level of consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity of industrial raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of skilled labour and experts</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems associated with economic planning are : inadquate skilled personnel, political instability, corruption and nepotism, poor implementaion plans etc.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1998>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of visible trade is the difference between the values of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">imported and exported goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imported and exported services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account and capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate of local and foreign currencies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The visible trade balance ( merchandise trade) is that part of the balance of trade figures that refers to international trade in physical goods. The balance is calculated as the value of visible exports less the value of visible imports.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1998>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a country has a balance of payments surplus on current account, this means that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total invisible export is greater than invisible import</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the value of goods exported must be greater than the value of goods imported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there must be a positive balance on capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the aggregate of the balance of trade and the invisible balance must be positive.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A balance of payments surplus on current account means that the country's total exports (both visible and invisible) are greater than its total imports (both visible and invisible). This is also known as a positive balance of trade and invisible balance. Visible exports and imports refer to the trade of goods, while invisible exports and imports refer to the trade of services.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1998>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a country operates a freely floating exchange rate system, and suffers a balance of payments deficit, the deficit can be eliminated through a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a rise in the external value of its currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fall in the external value of its currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the volume of imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the consumption of more foreign goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a country operates a freely floating exchange rate system, and suffers a balance of payments deficit, the deficit can be eliminated through a a fall in the external value of its currency.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>1998>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Commision for Africa was set up by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">UNO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OAU</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IMFS</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Commision for Africa was established by the Economic and Social Council of the UN in 1958 as one of the UN's five regional commissions.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}];
